# Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
solve <- function(rut) {
  clean <- toupper(gsub("[\.\-\s]", "", as.character(rut)))
  if (nchar(clean) < 2) return(FALSE)

  body <- substr(clean, 1, nchar(clean)-1)
  dv <- substr(clean, nchar(clean), nchar(clean))

  if (!grepl("^\\d+$", body)) return(FALSE)

  sum <- 0
  mul <- 2
  for (i in seq(nchar(body), 1, by=-1)) {
    d <- as.integer(substr(body, i, i))
    sum <- sum + d * mul
    mul <- if (mul == 7) 2 else (mul + 1)
  }

  mod <- 11 - (sum %% 11)
  dvCalc <- if (mod == 11) "0" else if (mod == 10) "K" else as.character(mod)
  dv == dvCalc
}

