# R · readr
# install.packages("readr")
library(readr)

solve <- function(input="input.csv", output="output.csv") {
  df <- read_csv(input, show_col_types = FALSE)
  if ("Email" %in% names(df)) df$Email <- tolower(trimws(df$Email))
  write_csv(df, output)
}

