# C0680 · Uso de teclado (keydown/atajos) (Intermedio, UI/Entrada)
# R: stdin (Enter)
solve <- function() {
  cat("Escribe una tecla y Enter (w/a/s/d, q):\n")
  repeat {
    line <- readline()
    if (nchar(line) == 0) next
    k <- tolower(substr(line, 1, 1))
    if (k == "q") break
    if (k == "w") cat("Mover: arriba\n")
    if (k == "s") cat("Mover: abajo\n")
    if (k == "a") cat("Mover: izquierda\n")
    if (k == "d") cat("Mover: derecha\n")
  }
}
